import React from "react";
import ParamCard from "./Tools/ParamCard";
import ParamHeader from "./Tools/ParamHeader";
import {THEME_COLORS} from "./Tools/Constants";

function Selector({
    value = 3,
    min = 1,
    max = 5,
    onChange,
    iconName = 'Zap',
    colorIndex = 2,
    onIconClick
}) {
    const options = Array.from({ length: max - min + 1 }, (_, i) => min + i);

    return (
        <ParamCard>
            <div className="flex items-center justify-between mb-3">
                <ParamHeader
                    label="速度"
                    iconName={iconName}
                    colorIndex={colorIndex}
                    onIconClick={onIconClick}
                />
            </div>
            <div className="flex gap-2">
                {options.map((speed) => (
                    <button
                        key={speed}
                        onClick={() => onChange(speed)}
                        className={`flex-1 py-2 rounded-xl font-bold transition-all ${
                            value === speed
                                ? `bg-gradient-to-r ${THEME_COLORS[colorIndex].gradient} text-white shadow-lg scale-110`
                                : 'bg-white/80 text-gray-600 hover:bg-white hover:scale-105'
                        }`}
                    >
                        {speed}
                    </button>
                ))}
            </div>
        </ParamCard>
    );
}

export default Selector
